+        for i in 0..n_scopes {
+            let id = ScopeId(format!("worker:evt{i}"));
+            tree.register(id.clone(), ScopeTier::Worker, &ScopeId::root(), format!("e{i}"), 1000).unwrap();
+            tree.start(&id, 1100).unwrap();
+            coord.register_scope(&id, ScopeTier::Worker, Some(&ScopeId::root())).unwrap();
+            scope_ids.push(id);
+        }
